memberdef.initializer:
do{                                        \
    if((__HANDLE__)->Lock == HAL_LOCKED)   \
    {                                      \
       return HAL_BUSY;                    \
    }                                      \
    else                                   \
    {                                      \
       (__HANDLE__)->Lock = HAL_LOCKED;    \
    }                                      \
  }while (0)
